supervisor_t g_efload_supervisor;

static uint16_t s_adc_dma_buffer[EFLOAD_ADC_CHANNEL_COUNT];

static float adc_count_to_pin_v(uint16_t raw)
{
    return ((float)raw / EFLOAD_BOARD_ADC_FULL_SCALE_COUNT) * EFLOAD_BOARD_ADC_REF_V;
}

static float adc_read_bipolar(uint32_t index, float gain, float sign)
{
    const float pin_v = adc_count_to_pin_v(s_adc_dma_buffer[index]);
    return (pin_v - EFLOAD_BOARD_ADC_BIPOLAR_MID_V) * gain * sign;
}

static float adc_read_unipolar(uint32_t index, float gain)
{
    const float pin_v = adc_count_to_pin_v(s_adc_dma_buffer[index]);
    return pin_v * gain;
}

static bool port_adc_read(hal_adc_frame_t *frame, void *context)
{
    (void)context;

    if (frame == 0) {
        return false;
    }

    frame->cvcf_phase_voltage_v.a =
        adc_read_bipolar(EFLOAD_ADC_IDX_CVCF_VA, EFLOAD_GAIN_CVCF_VA_V_PER_V, EFLOAD_SIGN_CVCF_VA);
    frame->cvcf_phase_voltage_v.b =
        adc_read_bipolar(EFLOAD_ADC_IDX_CVCF_VB, EFLOAD_GAIN_CVCF_VB_V_PER_V, EFLOAD_SIGN_CVCF_VB);
    frame->cvcf_phase_voltage_v.c =
        adc_read_bipolar(EFLOAD_ADC_IDX_CVCF_VC, EFLOAD_GAIN_CVCF_VC_V_PER_V, EFLOAD_SIGN_CVCF_VC);

    frame->cvcf_phase_current_a.a =
        adc_read_bipolar(EFLOAD_ADC_IDX_CVCF_IA, EFLOAD_GAIN_CVCF_IA_A_PER_V, EFLOAD_SIGN_CVCF_IA);
    frame->cvcf_phase_current_a.b =
        adc_read_bipolar(EFLOAD_ADC_IDX_CVCF_IB, EFLOAD_GAIN_CVCF_IB_A_PER_V, EFLOAD_SIGN_CVCF_IB);
    frame->cvcf_phase_current_a.c =
        adc_read_bipolar(EFLOAD_ADC_IDX_CVCF_IC, EFLOAD_GAIN_CVCF_IC_A_PER_V, EFLOAD_SIGN_CVCF_IC);

    frame->rectifier_phase_voltage_v.a =
        adc_read_bipolar(EFLOAD_ADC_IDX_RECT_VA, EFLOAD_GAIN_RECT_VA_V_PER_V, EFLOAD_SIGN_RECT_VA);
    frame->rectifier_phase_voltage_v.b =
        adc_read_bipolar(EFLOAD_ADC_IDX_RECT_VB, EFLOAD_GAIN_RECT_VB_V_PER_V, EFLOAD_SIGN_RECT_VB);
    frame->rectifier_phase_voltage_v.c =
        adc_read_bipolar(EFLOAD_ADC_IDX_RECT_VC, EFLOAD_GAIN_RECT_VC_V_PER_V, EFLOAD_SIGN_RECT_VC);

    frame->rectifier_phase_current_a.a =
        adc_read_bipolar(EFLOAD_ADC_IDX_RECT_IA, EFLOAD_GAIN_RECT_IA_A_PER_V, EFLOAD_SIGN_RECT_IA);
    frame->rectifier_phase_current_a.b =
        adc_read_bipolar(EFLOAD_ADC_IDX_RECT_IB, EFLOAD_GAIN_RECT_IB_A_PER_V, EFLOAD_SIGN_RECT_IB);
    frame->rectifier_phase_current_a.c =
        adc_read_bipolar(EFLOAD_ADC_IDX_RECT_IC, EFLOAD_GAIN_RECT_IC_A_PER_V, EFLOAD_SIGN_RECT_IC);

    frame->dc_bus_v = adc_read_unipolar(EFLOAD_ADC_IDX_DC_BUS, EFLOAD_GAIN_DC_BUS_V_PER_V);
    return true;
}

static uint32_t duty_to_compare(float duty, uint32_t period_counts)
{
    if (duty < 0.0f) {
        duty = 0.0f;
    }
    if (duty > 1.0f) {
        duty = 1.0f;
    }
    return (uint32_t)(duty * (float)period_counts);
}

