void efload_port_init(void)
{
    supervisor_config_t config;
    supervisor_default_config(&config);

    config.ts = 1.0f / EFLOAD_BOARD_CONTROL_FREQUENCY_HZ;
    config.dc_bus_min_v = EFLOAD_BOARD_DC_BUS_MIN_V;
    config.dc_bus_max_v = EFLOAD_BOARD_DC_BUS_MAX_V;
    config.phase_current_limit_a = EFLOAD_BOARD_PHASE_CURRENT_LIMIT_A;

    const supervisor_io_t io = {
        .adc = {
            .read = port_adc_read,
            .context = 0,
        },
        .pwm = {
            .update_duties = port_pwm_update,
            .enable = port_pwm_enable,
            .disable = port_pwm_disable,
            .set_deadtime_ns = port_pwm_set_deadtime_ns,
            .context = 0,
        },
        .timer = {
            .now_us = port_timer_now_us,
            .context = 0,
        },
        .gpio = {
            .set_status_led = port_gpio_set_led,
            .read_estop = port_gpio_read_estop,
            .context = 0,
        },
        .protection = {
            .read_latched = port_protection_read_latched,
            .clear_latched = port_protection_clear_latched,
            .context = 0,
        },
    };

    supervisor_init(&g_efload_supervisor, &config, io);
    (void)port_pwm_set_deadtime_ns(EFLOAD_BOARD_PWM_DEADTIME_NS, 0);
}

void efload_port_start(void)
{
    supervisor_request_start(&g_efload_supervisor);
}

void efload_port_stop(void)
{
    supervisor_request_stop(&g_efload_supervisor);
}

void efload_port_clear_fault(void)
{
    supervisor_clear_fault(&g_efload_supervisor);
}

void efload_port_on_control_period(void)
{
    supervisor_on_pwm_period(&g_efload_supervisor);
}

